def get_ls_result(dir_path: str) -> str:
    try:
        # Validate and normalize the directory path
        normalized_path = os.path.realpath(os.path.abspath(dir_path))

        # Ensure the path exists and is a directory
        if not os.path.isdir(normalized_path):
            return ''

        # Use os.scandir to list directory contents without subprocess
        lines = []
        with os.scandir(normalized_path) as entries:
            for entry in sorted(entries, key=lambda e: e.name):
                try:
                    info = entry.stat(follow_symlinks=False)
                    # Determine file type character
                    mode = info.st_mode
                    if stat.S_ISDIR(mode):
                        type_char = 'd'
                    elif stat.S_ISLNK(mode):
                        type_char = 'l'
                    elif stat.S_ISFIFO(mode):
                        type_char = 'p'
                    elif stat.S_ISSOCK(mode):
                        type_char = 's'
                    elif stat.S_ISBLK(mode):
                        type_char = 'b'
                    elif stat.S_ISCHR(mode):
                        type_char = 'c'
                    else:
                        type_char = '-'

                    # Build permission string
                    perms = stat.filemode(mode)

                    nlink = info.st_nlink
                    uid = info.st_uid
                    gid = info.st_gid
                    size = info.st_size

                    import datetime
                    mtime = datetime.datetime.fromtimestamp(info.st_mtime)
                    month = mtime.strftime('%b')
                    day = mtime.strftime('%d')
                    time_str = mtime.strftime('%H:%M')

                    line = f"{perms} {nlink:3d} {uid:5d} {gid:5d} {size:8d} {month} {day} {time_str} {entry.name}"
                    lines.append(line)
                except (OSError, PermissionError):
                    continue

        return '\n'.join(lines) + ('\n' if lines else '')
    except Exception:
        return ''

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    import ast
    import operator

    # Supported operators
    allowed_operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
        ast.Mod: operator.mod,
        ast.FloorDiv: operator.floordiv,
    }

    def safe_eval(node):
        if isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            else:
                raise ValueError("Unsupported constant type")
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in allowed_operators:
                raise ValueError(f"Unsupported operator: {op_type}")
            left = safe_eval(node.left)
            right = safe_eval(node.right)
            return allowed_operators[op_type](left, right)
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in allowed_operators:
                raise ValueError(f"Unsupported operator: {op_type}")
            operand = safe_eval(node.operand)
            return allowed_operators[op_type](operand)
        else:
            raise ValueError(f"Unsupported node type: {type(node)}")

    try:
        tree = ast.parse(expr, mode='eval')
        result = safe_eval(tree.body)
        return str(result)
    except Exception:
        return ""

