        return False

    # Password must contain at least one special character
    if not re.search(r'[!@#$%^&*(),.?":{}|<>_\-\[\]\\\/\'\`~;+=]', password):
        return False

    # Password must not contain spaces
    if ' ' in password:
        return False

    return True

